sourceQuery.expr:
label_join(
  (
    sum by (host.name, system.device) (
      system.filesystem.usage{system.filesystem.state="free"}
    )
    / ignoring(system.filesystem.state)
    sum by (host.name, system.device) (
      delta(system.filesystem.usage{system.filesystem.state="used"}[$__range]) / $__range_s
    )
  ) 
  and ignoring(system.filesystem.state)
  sum by (host.name, system.device) (
    delta(system.filesystem.usage{system.filesystem.state="used"}[$__range])
  ) > 0,
  "id", ":", "host.name", "system.device"
)

